impl Solution { pub fn result_array(nums: Vec<i32>, k: i32) -> Vec<i64> { let n = nums.len(); let k = k as usize; let mut black_res = vec![0i64; k]; let mut black_dp = vec![0i64; k]; for &black_x in &nums { let black_val = (black_x as usize % k); let mut black_next = vec![0i64; k]; black_next[black_val] += 1; for black_r in 0..k { if black_dp[black_r] > 0 { black_next[(black_r * black_val) % k] += black_dp[black_r]; } } for black_r in 0..k { black_res[black_r] += black_next[black_r]; } black_dp = black_next; } black_res } }